parameters.jsCode:
const payload = $('Wasup Inbound Webhook').first().json.body || $('Wasup Inbound Webhook').first().json;
const fromPhone = payload.from_phone || payload.from || payload.number || payload.phone || '';
const toPhone = payload.to_phone || payload.to || $('Workflow Config + Nordkone2 Prompt').first().json.fallbackFromPhone;
const message = String(payload.message || payload.text || payload.body || '').trim();
return [{ json: { payload, fromPhone, toPhone, message } }];

const config = $('Workflow Config + Nordkone2 Prompt').first().json;
const inbound = $('Prepare Inbound').first().json;
const listing = $json.listings?.[0] || null;
const listingText = listing ? [
  `Kone: ${listing.machine_title}`,
  `Nettikone ID: ${listing.nettikone_id}`,
  `URL: ${listing.listing_url}`,
  `Hinta: ${listing.price_text || 'ei tiedossa'}`,
  `Sijainti: ${listing.location || 'ei tiedossa'}`,
  `Vuosimalli: ${listing.model_year || 'ei tiedossa'}`,
  `Kuvaus: ${listing.description || 'ei kuvausta'}`
].join('\n') : 'Koneen tietoja ei löytynyt numerolla. Vastaa silti yleisen NordKone-kontekstin mukaan.';

const agentUserPrompt = `Asiakkaan viimeisin WhatsApp-viesti:\n${inbound.message}\n\nKonteksti viimeisimmästä outbound-kontaktista / Nettikone-listauksesta:\n${listingText}\n\nTee kaksi asiaa:\n1) Päätä classification ja needs_human.\n2) Kirjoita asiakkaalle lyhyt WhatsApp-vastaus NordKoneen me-muodossa.\n\nMuista palauttaa vain JSON.`;

return [{
  json: {
    ...inbound,
    listing,
    config,
    agentSystemPrompt: config.agentSystemPrompt,
    agentUserPrompt
  }
}];

const source = String($json.output || $json.text || $json.response || '').trim();
let parsed;
try {
  parsed = JSON.parse(source.replace(/^```json\s*/i, '').replace(/```$/i, '').trim());
} catch (error) {
  parsed = {
    reply_message: 'Kiitos viestistä! Välitän tämän meidän tiimille, niin voimme katsoa asian.',
    classification: 'needs_human',
    needs_human: true
  };
}
const allowed = new Set(['interested', 'sold', 'not_interested', 'opted_out', 'unclear', 'needs_human']);
if (!allowed.has(parsed.classification)) parsed.classification = 'needs_human';
parsed.needs_human = Boolean(parsed.needs_human || parsed.classification === 'interested' || parsed.classification === 'needs_human');
parsed.reply_message = String(parsed.reply_message || '').trim() || 'Kiitos viestistä! Välitän tämän meidän tiimille, niin voimme katsoa asian.';
const inbound = $('Build Agent Input').first().json;
return [{ json: { ...inbound, agentResult: parsed } }];

